     5→
     6→type ToastType = 'success' | 'error' | 'info' | 'warning';
     7→
     8→interface Toast {
     9→    id: string;
    10→    message: string;
    11→    type: ToastType;
    12→}
    13→
    14→interface ToastContextType {
    15→    toasts: Toast[];
    16→    addToast: (message: string, type?: ToastType) => void;
    17→    removeToast: (id: string) => void;
    18→}
    19→
    20→const ToastContext = createContext<ToastContextType | null>(null);
    21→
    22→export function useToast() {
    23→    const context = useContext(ToastContext);
    24→    if (!context) {
    25→        throw new Error('useToast must be used within a ToastProvider');
    26→    }
    27→    return context;
    28→}
    29→
    30→export function ToastProvider({ children }: { children: ReactNode }) {
    31→    const [toasts, setToasts] = useState<Toast[]>([]);
    32→
    33→    const addToast = useCallback((message: string, type: ToastType = 'info') => {
    34→        const id = Math.random().toString(36).substring(7);
    35→        setToasts(prev => [...prev, { id, message, type }]);
    36→
    37→        // Auto-remove after 5 seconds
    38→        setTimeout(() => {
    39→            setToasts(prev => prev.filter(t => t.id !== id));
    40→        }, 5000);
    41→    }, []);
    42→
    43→    const removeToast = useCallback((id: string) => {
    44→        setToasts(prev => prev.filter(t => t.id !== id));
    45→    }, []);
    46→
    47→    return (
    48→        <ToastContext.Provider value={{ toasts, addToast, removeToast }}>
    49→            {children}
    50→            <ToastContainer toasts={toasts} removeToast={removeToast} />
    51→        </ToastContext.Provider>
    52→    );
    53→}
    54→
    55→function ToastContainer({ toasts, removeToast }: { toasts: Toast[]; removeToast: (id: string) => void }) {
    56→    if (toasts.length === 0) return null;
    57→
    58→    return (
    59→        <div className="fixed bottom-4 left-4 z-50 flex flex-col gap-2 max-w-sm">
    60→            {toasts.map(toast => (
    61→                <ToastItem key={toast.id} toast={toast} onClose={() => removeToast(toast.id)} />
    62→            ))}
    63→        </div>
    64→    );
    65→}
    66→
    67→function ToastItem({ toast, onClose }: { toast: Toast; onClose: () => void }) {
    68→    const icons = {
    69→        success: <CheckCircle className="h-5 w-5 text-green-500" />,
    70→        error: <AlertCircle className="h-5 w-5 text-red-500" />,
    71→        warning: <AlertTriangle className="h-5 w-5 text-yellow-500" />,
    72→        info: <Info className="h-5 w-5 text-blue-500" />,
    73→    };
    74→
    75→    const bgColors = {
    76→        success: 'bg-green-50 border-green-200',
    77→        error: 'bg-red-50 border-red-200',
    78→        warning: 'bg-yellow-50 border-yellow-200',
    79→        info: 'bg-blue-50 border-blue-200',
