    82→    return (
    83→        <div
    84→            className={`flex items-center gap-3 p-4 rounded-lg border shadow-lg animate-in slide-in-from-left-5 fade-in duration-200 ${bgColors[toast.type]}`}
    85→        >
    86→            {icons[toast.type]}
    87→            <p className="text-sm font-medium flex-1">{toast.message}</p>
