     3→import { useState, useEffect } from 'react';
     4→import type { VRCapabilities } from '@/types/vr';
     5→
     6→/**
     7→ * Hook to detect WebXR support and device capabilities
     8→ *
     9→ * This hook detects:
    10→ * - WebXR API support
    11→ * - VR headset availability
    12→ * - AR support
    13→ * - WebGL version support
    14→ * - Device type (mobile/desktop)
    15→ * - Performance characteristics
    16→ *
    17→ * @returns {VRCapabilities} Object containing device capability flags
    18→ *
    19→ * @example
    20→ * ```tsx
    21→ * const capabilities = useVRCapabilities();
    22→ *
    23→ * if (capabilities.hasWebXRSupport) {
    24→ *   // Render VR experience
    25→ * } else {
    26→ *   // Show fallback
    27→ * }
    28→ * ```
    29→ */
    30→export function useVRCapabilities(): VRCapabilities {
    31→  const [capabilities, setCapabilities] = useState<VRCapabilities>({
    32→    hasWebXRSupport: false,
    33→    hasVRHeadset: false,
    34→    hasARSupport: false,
    35→    hasHandTracking: false,
    36→    hasControllers: false,
    37→    displayMode: 'none',
    38→    supportsWebGL2: false,
    39→    isMobile: false,
    40→    devicePixelRatio: 1,
    41→  });
    42→
    43→  useEffect(() => {
    44→    const detectCapabilities = async () => {
    45→      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
    46→        navigator.userAgent
    47→      );
    48→      const devicePixelRatio = window.devicePixelRatio || 1;
    49→
    50→      // Check WebGL support
    51→      const canvas = document.createElement('canvas');
    52→      const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
    53→      const supportsWebGL2 = !!canvas.getContext('webgl2');
    54→
    55→      // Check max texture size for performance estimation
    56→      let maxTextureSize: number | undefined;
    57→      if (gl) {
    58→        maxTextureSize = gl.getParameter(gl.MAX_TEXTURE_SIZE);
    59→      }
    60→
    61→      // Estimate performance level based on device characteristics
    62→      let performanceLevel: 'high' | 'medium' | 'low' = 'medium';
    63→      if (maxTextureSize && maxTextureSize >= 16384 && !isMobile) {
    64→        performanceLevel = 'high';
    65→      } else if (maxTextureSize && maxTextureSize < 8192 || isMobile) {
    66→        performanceLevel = 'low';
    67→      }
    68→
    69→      // Check WebXR support
    70→      if ('xr' in navigator) {
    71→        const xr = (navigator as any).xr;
    72→
    73→        try {
    74→          // Check VR support
    75→          const vrSupported = await xr.isSessionSupported('immersive-vr');
    76→          let arSupported = false;
    77→
    78→          // Check AR support
    79→          try {
    80→            arSupported = await xr.isSessionSupported('immersive-ar');
    81→          } catch (err) {
    82→            // AR not supported
    83→          }
    84→
    85→          const hasWebXRSupport = vrSupported || arSupported;
    86→          const displayMode = vrSupported ? 'immersive-vr' : arSupported ? 'immersive-ar' : 'inline';
    87→
    88→          // For headset detection, we need to check if VR is supported and not on mobile
    89→          // Mobile devices support WebXR but aren't headsets
    90→          const hasVRHeadset = vrSupported && !isMobile;
    91→
    92→          // Check for advanced features (hand tracking and controllers)
    93→          // These require an active session to fully detect, so we make best guesses
    94→          const hasHandTracking = false; // Would need active session to detect
    95→          const hasControllers = hasVRHeadset; // Headsets typically have controllers
    96→
    97→          setCapabilities({
    98→            hasWebXRSupport,
    99→            hasVRHeadset,
   100→            hasARSupport: arSupported,
   101→            hasHandTracking,
   102→            hasControllers,
   103→            displayMode,
   104→            maxTextureSize,
   105→            supportsWebGL2,
   106→            performanceLevel,
   107→            isMobile,
   108→            devicePixelRatio,
   109→          });
   110→        } catch (err) {
   111→          // WebXR API exists but session support check failed
   112→          setCapabilities({
   113→            hasWebXRSupport: false,
   114→            hasVRHeadset: false,
   115→            hasARSupport: false,
   116→            hasHandTracking: false,
   117→            hasControllers: false,
   118→            displayMode: 'inline',
   119→            maxTextureSize,
   120→            supportsWebGL2,
   121→            performanceLevel,
   122→            isMobile,
   123→            devicePixelRatio,
   124→          });
   125→        }
   126→      } else {
   127→        // No WebXR support at all
   128→        setCapabilities({
   129→          hasWebXRSupport: false,
   130→          hasVRHeadset: false,
   131→          hasARSupport: false,
   132→          hasHandTracking: false,
   133→          hasControllers: false,
   134→          displayMode: 'none',
   135→          maxTextureSize,
   136→          supportsWebGL2,
   137→          performanceLevel,
   138→          isMobile,
   139→          devicePixelRatio,
   140→        });
   141→      }
   142→    };
   143→
   144→    detectCapabilities();
   145→  }, []);
   146→
   147→  return capabilities;
   148→}
